"""Emission compliance tests for schemas (auto-generated by pact)."""

from schemas.schemas import Schemas


class TestEmissionCompliance:
    """Verify schemas emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_severity_rank_emits_events(self):
        """Method severity_rank emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = Schemas(event_handler=handler)
        try:
            obj.severity_rank()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for severity_rank'
        assert len(completed) >= 1, 'No completed/error event for severity_rank'
        assert invoked[0].get("pact_key") == "PACT:schemas:severity_rank"
        assert isinstance(invoked[0].get("input_classification"), list)

