    def test_pact_key_format(self):
        """All emitted events have correctly formatted PACT keys."""
        events, handler = self._make_handler()
        obj = Schemas(event_handler=handler)
        try:
            obj.severity_rank()
        except (TypeError, Exception):
            pass
        try:
            obj.confidence_rank()
        except (TypeError, Exception):
            pass
        try:
            obj.learner_phase_rank()
        except (TypeError, Exception):
            pass
        try:
            obj.canonical_bytes()
        except (TypeError, Exception):
            pass
        try:
            obj.canonical_hash()
        except (TypeError, Exception):
            pass
        try:
            obj.validate_iso_timestamp()
        except (TypeError, Exception):
            pass
        for event in events:
            key = event.get("pact_key", "")
            assert key.startswith("PACT:schemas:"), f"Bad pact_key: {key}"

